/// @nodoc
class FieldFilterOperator {
  static const lessThan = FieldFilterOperator._('LESS_THAN');
  static const greaterThan = FieldFilterOperator._('GREATER_THAN');
  static const between = FieldFilterOperator._('BETWEEN');
