  static const notEqualTo = FieldFilterOperator._('NOT_EQUAL_TO');
  static const greaterThanOrEqualTo =
      FieldFilterOperator._('GREATER_THAN_OR_EQUAL_TO');
  static const lessThanOrEqualTo =
      FieldFilterOperator._('LESS_THAN_OR_EQUAL_TO');
  static const contains = FieldFilterOperator._('CONTAINS');
  static const orderBy = FieldFilterOperator._('ORDER_BY');

  final String value;

  const FieldFilterOperator._(this.value);

  static const values = [
    lessThan,
    greaterThan,
    between,
    equalTo,
    notEqualTo,
    greaterThanOrEqualTo,
    lessThanOrEqualTo,
    contains,
    orderBy
  ];

  static FieldFilterOperator fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => FieldFilterOperator._(value));

  @override
  bool operator ==(other) =>
      other is FieldFilterOperator && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

